INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 155, "東山奈央", "人助け、応援", 2, 16, 8, "A", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, 27, "人助けが大好き！　前向き格闘娘", 100101, "トゥインクルウィッシュ", 0, "ヒヨリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 158, "種田梨沙", "料理、人間観察", 2, 17, 4, "O", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, 5, "戦闘のサポートが得意な、心優しい少女", 100201, "トゥインクルウィッシュ", 0, "ユイ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 163, "早見沙織", "読書、乗馬、お茶", 2, 18, 1, "B", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, 12, "クールで何事にも真っ直ぐな剣士", 100301, "トゥインクルウィッシュ", 0, "レイ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 128, "諸星すみれ", "いたずら、探検", 5, 9, 8, "O", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 27, 10, "探検好きのイタズラっ子", 100401, "リトルリリカル", 0, "ミソギ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 146, "下田麻美", "ヒーローごっこ", 8, 12, 11, "O", "？？？", 40, 25, "ヒーローに憧れる騎士見習いの少女", 100501, "王宮騎士団（NIGHTMARE）", 0, "マツリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 150, "浅倉杏美", "サックス", 7, 13, 11, "O", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 42, 22, "甘え上手なみんなの人気者", 100601, "悪魔偽王国軍（ディアボロス）", 0, "アカリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 130, "雨宮天", "プリンを食べること", 7, 14, 1, "B", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, 23, "プリン大好きゴースト娘", 100701, "悪魔偽王国軍（ディアボロス）", 0, "ミヤコ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 150, "大空直美", "鏡で自分を見ること", 15, 14, 10, "AB", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 40, 10, "ボクは誰よりも美しい", 100801, "ヴァイスフリューゲル　ランドソル支部", 0, "ユキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 159, "髙野麻美", "小説執筆", 13, 17, 7, "A", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 45, 5, "前世を信じる中二病患者、「疾風の冥姫」", 100901, "トワイライトキャラバン", 0, "アンナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 155, "内田真礼", "空想、ぬいぐるみ集め", 10, 16, 9, "O", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 42, 22, "マホマホ王国のプリンセス", 101001, "自警団（カォン）", 0, "マホ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 156, "阿澄佳奈", "お裁縫", 3, 15, 8, "A", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 44, 25, "人懐っこくてマシンガントークな妹系少女", 101101, "ラビリンス", 0, "リノ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 156, "大橋彩香", "妹と遊ぶこと、二度寝、昼寝、早寝", 6, 17, 12, "A", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 46, 24, "みんなのために超能力を使う眠り姫", 101201, "フォレスティエ", 0, "ハツネ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 166, "佳村はるか", "読書、魔法", 13, 18, 8, "O", "", 55, 21, "オタク全開な魔法少女", 101301, "トワイライトキャラバン", 0, "ナナカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 152, "水瀬いのり", "読書、推理", 10, 15, 11, "AB", "test", 41, 3, "頭脳明晰な美少女名探偵", 101401, "自警団（カォン）", 0, "カスミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 165, "國府田マリ子", "絵本作り", 6, 21, 9, "O", "test", 54, 5, "母性溢れる優しいみんなの「ミサト先生」", 101501, "フォレスティエ", 0, "ミサト");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 167, "上坂すみれ", "ファッション", 14, 17, 4, "O", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 48, 10, "天真爛漫で人気者のカリスマモデル", 101601, "ルーセント学院", 0, "スズナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 158, "高森奈津美", "踊り、空手", 10, 17, 7, "A", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 53, 7, "いつでも「なんくるないさ～」な天然娘", 101701, "自警団（カォン）", 0, "カオリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 162, "伊藤静", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, 23, 8, "B", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 52, 14, "多くの男性を魅了する無垢な女教師", 101801, "ルーセント学院", 0, "イオ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 117, "日高里菜", "かわいいもの集め", 5, 10, 4, "O", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 21, 3, "お歌もにんじんも、ウサギさんも大好き♪", 102001, "リトルリリカル", 0, "ミミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 150, "植田佳奈", "観劇、おままごと", 9, 12, 6, "B", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, 9, "泣き虫で臆病な守ってあげたい女の子", 102101, "サレンディア救護院", 0, "クルミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 150, "原紗友里", "ゲーム全般", 7, 13, 11, "O", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 40, 22, "人見知りであまのじゃくな女の子", 102201, "悪魔偽王国軍（ディアボロス）", 0, "ヨリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 148, "芹澤優", "屋内でできる遊び", 9, 14, 5, "B", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, 10, "ぷうきちといつも一緒！", 102301, "サレンディア救護院", 0, "アヤネ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 154, "悠木碧", "ご奉仕", 9, 15, 12, "O", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 43, 12, "お嬢さまのためにがんばるドジっ娘メイド", 102501, "サレンディア救護院", 0, "スズメ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 144, "小岩井ことり", "あんパン", 11, 17, 1, "B", "test", 42, 1, "遊びと睡眠が何より大事なぐうたら娘", 102601, "牧場（エリザベスパーク）", 0, "リン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 154, "橋本ちなみ", "実験、裁縫、料理", 13, 16, 7, "B", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 30, "運命の相手に一途すぎる乙女", 102701, "トワイライトキャラバン", 0, "エリコ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 156, "堀江由衣", "経営、お茶会", 9, 17, 10, "A", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 43, 4, "救護院を経営する優しい庶民派お嬢様", 102801, "サレンディア救護院", 0, "サレン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 157, "日笠陽子", "舞台鑑賞、ダンス", 4, 17, 1, "B", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 40, 24, "歌って踊れる大人気アイドル", 102901, "カルミナ", 0, "ノゾミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "佐藤聡美", "忍法開発", 15, 16, 8, "O", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 51, 31, "トーゴクの神秘、オシエテクダサイ！", 103001, "ヴァイスフリューゲル　ランドソル支部", 0, "ニノン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 157, "大坪由佳", "占い", 7, 18, 12, "AB", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, 22, "占いが得意な霊能少女", 103101, "悪魔偽王国軍（ディアボロス）", 0, "シノブ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 157, "松嵜麗", "慈善事業", 12, 18, 3, "AB", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 45, 12, "一人前の商人を目指すパワフルお嬢様", 103201, "メルクリウス財団", 0, "アキノ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 142, "新田恵海", "漫才", 11, 20, 3, "B", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 35, 3, "みんなを笑顔にするお笑い牧場主", 103301, "牧場（エリザベスパーク）", 0, "マヒル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 164, "今井麻美", "ウインドーショッピング", 12, 22, 3, "A", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 55, 16, "純情でほっとけない大人の女性", 103401, "メルクリウス財団", 0, "ユカリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 118, "小倉唯", "お勉強", 5, 8, 2, "A", "test", 21, 2, "礼儀正しくしっかり者のちびっ子優等生", 103601, "リトルリリカル", 0, "キョウカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 149, "茅原実里", "剣術、年長者をからかう", 8, 13, 8, "A", "test", 43, 11, "義理堅くてからかい好きな剣術少女", 103701, "王宮騎士団（NIGHTMARE）", 0, "トモ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 153, "小清水亜美", "読書、お散歩", 11, 14, 11, "A", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 40, 3, "読書が趣味の病弱少女", 103801, "牧場（エリザベスパーク）", 0, "シオリ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 158, "花澤香菜", "友達作りのイメトレ", 6, 13, 6, "AB", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 44, 6, "「友達」に憧れる、エルフの森の女の子", 104001, "フォレスティエ", 0, "アオイ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "福原綾香", "各種楽器", 4, 17, 6, "O", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, 3, "人々を守るために歌う、唱喚士の少女", 104201, "カルミナ", 0, "チカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 168, "小松未可子", "お菓子作り", 10, 17, 8, "O", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 54, 9, "男勝りで情に厚いワイルド娘", 104301, "自警団（カォン）", 0, "マコト");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 172, "丹下桜", "世界征服", 7, "??", 5, "A", "test", 50, 5, "かつては夜を支配した最強の吸血鬼", 104401, "悪魔偽王国軍（ディアボロス）", 0, "イリヤ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 157, "長妻樹里", "小説を読むこと", 15, 18, 11, "AB", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 49, 19, "妄想大好き！　ほんとは照れ屋な女の子", 104501, "ヴァイスフリューゲル　ランドソル支部", 0, "クウカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 158, "沼倉愛美", "猫とたわむれること", 12, 19, 3, "AB", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 1, "弱きを助け強きをくじく猫娘", 104601, "メルクリウス財団", 0, "タマキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 171, "川澄綾子", "格闘技、湯浴み", 8, 25, 10, "A", "？？？", 50, 25, "素顔を見せない冷静沈着な女性騎士", 104701, "王宮騎士団（NIGHTMARE）", 0, "ジュン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "田所あずさ", "傭兵などのアルバイト", 12, 20, 11, "O", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, 11, "仕事も私事も効率優先な傭兵少女", 104801, "メルクリウス財団", 0, "ミフユ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 168, "生天目仁美", "家事全般", 3, 18, 10, "O", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, 24, "お姉ちゃんがお世話してあげるからねっ！", 104901, "ラビリンス", 0, "シズル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 120, "久野美咲", "ファッション誌鑑賞、コスメ集め", 14, 11, 1, "A", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 22, 3, "ちょっとおませな恋に恋する女の子", 105001, "ルーセント学院", 0, "ミサキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 166, "三石琴乃", "研究、実験", 13, 27, 3, "A", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 53, 7, "実験が趣味の危険な科学者", 105101, "トワイライトキャラバン", 0, "ミツキ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 150, "徳井青空", "毛繕い、お喋り", 11, 17, 3, "A", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 100, 14, "乙女チックなもふもふアニマル", 105201, "牧場（エリザベスパーク）", 0, "リマ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 140, "辻あゆみ", "お菓子屋通い", 15, 17, 7, "A", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 33, 28, "見た目も中身もお子ちゃまな異国の軍人", 105301, "ヴァイスフリューゲル　ランドソル支部", 0, "モニカ");
