INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 155, "大関英里", "観察", 15, 16, 4, "O", "test", 43, 7, "どこまでも一途に慕う、純情乙女", 105501, "ヴァイスフリューゲル　ランドソル支部", 0, "アユミ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 167, "佐藤利奈", "釣り", 13, 25, 7, "B", "test", 54, 11, "人情味溢れる粋でいなせな「姉御」", 105601, "トワイライトキャラバン", 0, "ルカ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 156, "金元寿子", "冒険、おしゃべり", "", 17, 3, "O", "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 45, 10, "空への冒険を夢見る騎空士の少女", 105701, "？？？", 0, "ジータ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 156, "M・A・O", "食べ歩き、料理", 1, 17, 3, "O", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 46, 31, "いつも元気な腹ペコ少女", 105801, "美食殿", 0, "ペコリーヌ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 140, "伊藤美来", "瞑想、動植物の飼育", 1, 11, 5, "B", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 35, 11, "主を慕う、小さなガイド役", 105901, "美食殿", 0, "コッコロ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 152, "立花理香", "猫と遊ぶ", 1, 14, 9, "A", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 39, 2, "行き倒れの謎のネコミミ魔法使い", 106001, "美食殿", 0, "キャル");
