INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 140, "伊藤美来", "瞑想、動植物の飼育", 1, 11, 5, "B", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 35, 11, "主を慕う、小さなガイド役", 107601, "美食殿", 0, "コッコロ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 154, "悠木碧", "ご奉仕", 9, 15, 12, "O", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 43, 12, "お嬢さまのためにがんばるドジっ娘メイド", 107701, "サレンディア救護院", 0, "スズメ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 152, "立花理香", "猫と遊ぶ", 1, 14, 9, "A", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 39, 2, "行き倒れの謎のネコミミ魔法使い", 107801, "美食殿", 0, "キャル（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 158, "沼倉愛美", "猫とたわむれること", 12, 19, 3, "AB", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 1, "弱きを助け強きをくじく猫娘", 107901, "メルクリウス財団", 0, "タマキ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "田所あずさ", "傭兵などのアルバイト", 12, 20, 11, "O", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, 11, "仕事も私事も効率優先な傭兵少女", 108001, "メルクリウス財団", 0, "ミフユ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 157, "大坪由佳", "占い", 7, 18, 12, "AB", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, 22, "占いが得意な霊能少女", 108101, "悪魔偽王国軍（ディアボロス）", 0, "シノブ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 130, "雨宮天", "プリンを食べること", 7, 14, 1, "B", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 32, 23, "プリン大好きゴースト娘", 108201, "悪魔偽王国軍（ディアボロス）", 0, "ミヤコ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 120, "久野美咲", "ファッション誌鑑賞、コスメ集め", 14, 11, 1, "A", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 22, 3, "ちょっとおませな恋に恋する女の子", 108301, "ルーセント学院", 0, "ミサキ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "福原綾香", "各種楽器", 4, 17, 6, "O", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, 3, "人々を守るために歌う、唱喚士の少女", 108401, "カルミナ", 0, "チカ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 150, "植田佳奈", "観劇、おままごと", 9, 12, 6, "B", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 40, 9, "泣き虫で臆病な守ってあげたい女の子", 108501, "サレンディア救護院", 0, "クルミ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 148, "芹澤優", "屋内でできる遊び", 9, 14, 5, "B", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 38, 10, "ぷうきちといつも一緒！", 108601, "サレンディア救護院", 0, "アヤネ（クリスマス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 155, "東山奈央", "人助け、応援", 2, 16, 8, "A", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 44, 27, "人助けが大好き！　前向き格闘娘", 108701, "トゥインクルウィッシュ", 0, "ヒヨリ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 158, "種田梨沙", "料理、人間観察", 2, 17, 4, "O", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 47, 5, "戦闘のサポートが得意な、心優しい少女", 108801, "トゥインクルウィッシュ", 0, "ユイ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 163, "早見沙織", "読書、乗馬、お茶", 2, 18, 1, "B", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 46, 12, "クールで何事にも真っ直ぐな剣士", 108901, "トゥインクルウィッシュ", 0, "レイ（ニューイヤー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 154, "橋本ちなみ", "実験、裁縫、料理", 13, 16, 7, "B", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 30, "運命の相手に一途すぎる乙女", 109001, "トワイライトキャラバン", 0, "エリコ（バレンタイン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 168, "生天目仁美", "家事全般", 3, 18, 10, "O", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, 24, "お姉ちゃんがお世話してあげるからねっ！", 109101, "ラビリンス", 0, "シズル（バレンタイン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 156, "日笠陽子", "読書", "", 17, 12, "AB", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 55, 1, "英霊と契約を結んだマナリアの天才王女", 109201, "？？？", 0, "アン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 144, "こやまきみこ", "食べること、眠ること", "", 16, 2, "O", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 45, 4, "マナリア魔法学院の新入生", 109301, "？？？", 0, "ルゥ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("半人半竜", 167, "福原綾香", "ピアノ", "", 17, 11, "B", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 67, 3, "人を超越した力を有す心優しい竜姫", 109401, "？？？", 0, "グレア");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 157, "長妻樹里", "小説を読むこと", 15, 18, 11, "AB", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 49, 19, "妄想大好き！　ほんとは照れ屋な女の子", 109501, "ヴァイスフリューゲル　ランドソル支部", 0, "クウカ（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "佐藤聡美", "忍法開発", 15, 16, 8, "O", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 51, 31, "トーゴクの神秘、オシエテクダサイ！", 109601, "ヴァイスフリューゲル　ランドソル支部", 0, "ニノン（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("鬼族", 154, "水瀬いのり", "演劇鑑賞、詩文", "", 17, 2, "?", "", "??", 2, "鬼がかりの万能妹メイド", 109701, "？？？", 0, "レム");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("鬼族", 154, "村川梨衣", "読書", "", 17, 2, "?", "", "??", 2, "毒舌系鬼姉メイド", 109801, "？？？", 0, "ラム");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ハーフエルフ", 164, "高橋李依", "パックの毛繕い、勉強", "", "??", 9, "?", "", "??", 23, "銀髪のおっとりハーフエルフ", 109901, "？？？", 0, "エミリア");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 167, "上坂すみれ", "ファッション", 14, 17, 4, "O", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 48, 10, "天真爛漫で人気者のカリスマモデル", 110001, "ルーセント学院", 0, "スズナ（サマー）");
