INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 158, "沼倉愛美", "猫とたわむれること", 12, 19, 3, "AB", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 1, "弱きを助け強きをくじく猫娘", 116801, "メルクリウス財団", 0, "タマキ（作業服）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "田所あずさ", "傭兵などのアルバイト", 12, 20, 11, "O", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 49, 11, "仕事も私事も効率優先な傭兵少女", 116901, "メルクリウス財団", 0, "ミフユ（作業服）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 154, "橋本ちなみ", "実験、裁縫、料理", 13, 16, 7, "B", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 43, 30, "運命の相手に一途すぎる乙女", 117001, "トワイライトキャラバン", 0, "エリコ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 168, "生天目仁美", "家事全般", 3, 18, 10, "O", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 54, 24, "お姉ちゃんがお世話してあげるからねっ！", 117101, "ラビリンス", 0, "シズル（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 157, "日笠陽子", "舞台鑑賞、ダンス", 4, 17, 1, "B", "", 40, 24, "歌って踊れる大人気アイドル", 117201, "カルミナ", 0, "ノゾミ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "福原綾香", "各種楽器", 4, 17, 6, "O", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 46, 3, "人々を守るために歌う、唱喚士の少女", 117301, "カルミナ", 0, "チカ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 153, "木戸衣吹", "裁縫", 4, 14, 9, "AB", "", 45, 7, "ファッション大好きなキュートガール", 117401, "カルミナ", 0, "ツムギ（サマー）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 166, "三石琴乃", "研究、実験", 13, 27, 3, "A", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 53, 7, "実験が趣味の危険な科学者", 117501, "トワイライトキャラバン", 0, "ミツキ（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("エルフ", 150, "大空直美", "鏡で自分を見ること", 15, 14, 10, "AB", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 40, 10, "ボクは誰よりも美しい", 117601, "ヴァイスフリューゲル　ランドソル支部", 0, "ユキ（オーエド）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 158, "高森奈津美", "踊り、空手", 10, 17, 7, "A", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 53, 7, "いつでも「なんくるないさ～」な天然娘", 117701, "自警団（カォン）", 0, "カオリ（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 163, "佐藤聡美", "忍法開発", 15, 16, 8, "O", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 51, 31, "トーゴクの神秘、オシエテクダサイ！", 117801, "ヴァイスフリューゲル　ランドソル支部", 0, "ニノン（ハロウィン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 167, "上坂すみれ", "ファッション", 14, 17, 4, "O", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 48, 10, "天真爛漫で人気者のカリスマモデル", 117901, "ルーセント学院", 0, "スズナ（ハロウィン）");
