INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 162, "伊藤静", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, 23, 8, "B", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 52, 14, "多くの男性を魅了する無垢な女教師", 119001, "ルーセント学院", 0, "イオ（ノワール）");
