INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 159, "髙野麻美", "小説執筆", 13, 17, 7, "A", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 45, 5, "前世を信じる中二病患者、「疾風の冥姫」", 121901, "トワイライトキャラバン", 0, "アンナ（パイレーツ）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("魔族", 157, "大坪由佳", "占い", 7, 18, 12, "AB", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 42, 22, "占いが得意な霊能少女", 122001, "悪魔偽王国軍（ディアボロス）", 0, "シノブ（パイレーツ）");
