INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("ヒューマン", 128, "諸星すみれ", "いたずら、探検", 5, 9, 8, "O", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 27, 10, "探検好きのイタズラっ子", 122801, "リトルリリカル", 0, "ミソギ（サマー）");
