INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("獣人族", 158, "沼倉愛美", "猫とたわむれること", 12, 19, 3, "AB", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 48, 1, "弱きを助け強きをくじく猫娘", 125101, "メルクリウス財団", 0, "タマキ（カフェ）");
